const prices=document.querySelectorAll(".services-prices"),hoverClass="services-prices_hover",clearHovers=()=>prices.forEach((e=>{e.classList.remove(hoverClass)}));prices.forEach((e=>{e.addEventListener("click",(()=>window.open(e.getAttribute("to"),"_self"))),e.addEventListener("mouseenter",(()=>{prices.forEach((e=>{e.classList.remove(hoverClass)})),e.classList.add(hoverClass)}))}));